    slug: 'teplarna-holesovice',
    localizedNames: { cz: 'Teplárna Holešovice', zh: '霍勒绍维采热电厂（Teplárna Holešovice）' },
    labels: ['historical', 'architecture'],
    coordinates: { lat: 50.10971142233254, lng: 14.436801702836597 },
