    name: 'Church of St. Peter and Paul (Bohnice)',
    slug: 'kostel-svateho-petra-a-pavla-bohnice',
    localizedNames: { cz: 'Kostel svatého Petra a Pavla (Bohnice)', zh: '圣伯多禄与圣保禄教堂（波赫尼采）' },
    labels: ['church', 'historical', 'architecture'],
