    name: 'Diamant House',
    slug: 'diamant-house',
    localizedNames: { cz: 'Dům Diamant', zh: '钻石大厦' },
    labels: ['modern', 'architecture'],
    coordinates: { lat: 50.08392161870126, lng: 14.4245418122088694 },
