    name: 'House of the Diamond',
    slug: 'dum-diamant',
    localizedNames: { cz: 'Dům Diamant', zh: '钻石之家' },
    labels: ['architecture', 'historical'],
    coordinates: { lat: 50.079335559660635, lng: 14.419919742887998 },
