    name: 'Black Rose House',
    slug: 'cerna-ruze',
    localizedNames: { cz: 'Černá Růže (Dům U Černé růže)', zh: '黑玫瑰之家' },
    labels: ['architecture', 'historical'],
    coordinates: { lat: 50.085118867769324, lng: 14.425266168600404 },
