    name: 'Fruit Market Square',
    slug: 'ovocny-trh',
    localizedNames: { cz: 'Ovocný trh', zh: '果品市场广场' },
    labels: ['square', 'historical'],
    coordinates: { lat: 50.08667686968571, lng: 14.4250759979213 },
    rarity: 'rare',
