    name: 'Army Museum Žižkov',
    slug: 'armadni-muzeum-zizkov',
    localizedNames: { cz: 'Armádní muzeum Žižkov', zh: '日什科夫军事博物馆' },
    labels: ['museum', 'historical'],
    coordinates: { lat: 50.08754521037309, lng: 14.444658294652788 },
