    name: 'Ohrada (Žižkov)',
    slug: 'ohrada-zizkov',
    localizedNames: { cz: 'Ohrada (Žižkov)', zh: '奥赫拉达（日什科夫）' },
    labels: ['street', 'historical', 'hidden-gem'],
    coordinates: { lat: 50.09008524278199, lng: 14.4677103649126 },
    rarity: 'epic',
