    name: 'Terezín Concentration Camp',
    slug: 'koncentracni-tabor-terezin',
    localizedNames: { cz: 'Koncentrační tábor Terezín', zh: '特雷津集中营' },
    labels: ['historical', 'monument'],
    coordinates: { lat: 50.51377897536429, lng: 14.16441309262809 },
    rarity: 'mythic',
