    name: 'Vyšehrad Railway Stop',
    slug: 'nadrazi-vysehrad',
    localizedNames: { cz: 'Železniční zastávka Praha-Vyšehrad', zh: '维谢赫拉德火车站' },
    labels: ['transport', 'historical'],
    coordinates: { lat: 50.067743692799155, lng: 14.420123468810086 },
